#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp,
    __global float *result,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int c_start = __get_global_id(0) * BLOCK_SIZE;
    int r_start = __get_global_id(1) * BLOCK_SIZE;

    int c_end = c_start + BLOCK_SIZE > col ? col : c_start + BLOCK_SIZE;
    int r_end = r_start + BLOCK_SIZE > row ? row : r_start + BLOCK_SIZE;

    for (int iter = 0; iter < num_iterations; iter++) {
        for (int r = r_start; r < r_end; ++r) {
            for (int c = c_start; c < c_end; ++c) {
                float delta;
                int idx = r * col + c;

                bool is_boundary = (r == 0) || (c == 0) || (r == row - 1) || (c == col - 1);

                if (is_boundary) {
                    if ((r == 0) && (c == 0)) {
                        delta = Cap_1 * (power[0] +
                            (temp[1] - temp[0]) * Rx_1 +
                            (temp[col] - temp[0]) * Ry_1 +
                            (amb_temp - temp[0]) * Rz_1);
                    }
                    else if ((r == 0) && (c == col - 1)) {
                        delta = Cap_1 * (power[c] +
                            (temp[c - 1] - temp[c]) * Rx_1 +
                            (temp[c + col] - temp[c]) * Ry_1 +
                            (amb_temp - temp[c]) * Rz_1);
                    }
                    else if ((r == row - 1) && (c == col - 1)) {
                        delta = Cap_1 * (power[idx] +
                            (temp[idx - 1] - temp[idx]) * Rx_1 +
                            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
                            (amb_temp - temp[idx]) * Rz_1);
                    }
                    else if ((r == row - 1) && (c == 0)) {
                        delta = Cap_1 * (power[r * col] +
                            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                            (temp[(r - 1) * col] - temp[r * col]) * Ry_1 +
                            (amb_temp - temp[r * col]) * Rz_1);
                    }
                    else if (r == 0) {
                        delta = Cap_1 * (power[c] +
                            (temp[c + 1] + temp[c - 1] - 2.0f * temp[c]) * Rx_1 +
                            (temp[col + c] - temp[c]) * Ry_1 +
                            (amb_temp - temp[c]) * Rz_1);
                    }
                    else if (c == col - 1) {
                        delta = Cap_1 * (power[idx] +
                            (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                            (temp[idx - 1] - temp[idx]) * Rx_1 +
                            (amb_temp - temp[idx]) * Rz_1);
                    }
                    else if (r == row - 1) {
                        delta = Cap_1 * (power[idx] +
                            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                            (temp[(r - 1) * col + c] - temp[idx]) * Ry_1 +
                            (amb_temp - temp[idx]) * Rz_1);
                    }
                    else if (c == 0) {
                        delta = Cap_1 * (power[r * col] +
                            (temp[(r + 1) * col] + temp[(r - 1) * col] - 2.0f * temp[r * col]) * Ry_1 +
                            (temp[r * col + 1] - temp[r * col]) * Rx_1 +
                            (amb_temp - temp[r * col]) * Rz_1);
                    }
                } else {
                    delta = Cap_1 * (power[idx] +
                        (temp[(r + 1) * col + c] + temp[(r - 1) * col + c] - 2.0f * temp[idx]) * Ry_1 +
                        (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
                        (amb_temp - temp[idx]) * Rz_1);
                }

                result[idx] = temp[idx] + delta;
            }
        }
    }
}
